        .init(artist: "carole king", album: "tapestry", texts: ["25 миллионов копий. Альбом, после которого песни-исповеди стали жанром.", "До этого Кинг была автором песен для других. «Tapestry» — её первый альбом как солистки."]),
        .init(artist: "neil young", album: "harvest", texts: ["«Heart of Gold». Самый продаваемый альбом Янга. И самый ненавистный для самого Янга.", "Янг говорил, что «Heart of Gold» поставил его в середину дороги — и он немедленно свернул в кювет."]),
        .init(artist: "neil young", album: "after the gold rush", texts: ["До «Harvest». Тоньше, грустнее.", "17-летний Нил Лофгрин играл на пианино в нескольких треках. Потом стал гитаристом E Street Band."]),
        .init(artist: "the eagles", album: "hotel california", texts: ["Альбом-стандарт мягкого рока. Заглавная песня — про что — спорят до сих пор.", "Двойное гитарное соло в конце трека Дон Фелдер и Джо Уолш играли по 16 нот в секунду. Записывали по 3 минуты за дубль."]),
        .init(artist: "fleetwood mac", album: "rumours", texts: ["Группа разваливалась изнутри. Все спали со всеми не теми. Альбом получился великолепным.", "40 миллионов копий — один из самых продаваемых альбомов в истории. И весь — про чужие любовные истории внутри группы."]),
        .init(artist: "bruce springsteen", album: "born to run", texts: ["Альбом, на котором Спрингстин стал «Боссом». Эпичный рок Нью-Джерси.", "Спрингстин работал над альбомом 14 месяцев и едва не сошёл с ума. Записал всё с нуля несколько раз."]),
        .init(artist: "bruce springsteen", album: "darkness on the edge of town", texts: ["После «Born to Run» — тише, тяжелее, темнее.", "Альбом задержали на три года из-за судебного процесса с менеджером. Спрингстин в это время выступал каждую ночь."]),
        .init(artist: "steely dan", album: "aja", texts: ["Безупречно записанный альбом. Сессионные музыканты высшего класса.", "Группа отбирала музыкантов как тренер бейсбольную команду. Иногда заставляли записывать соло по 30 раз."]),
        .init(artist: "genesis", album: "the lamb lies down on broadway", texts: ["Последний альбом с Питером Гэбриэлом. Двойной концепт о Нью-Йорке.", "Через тур после релиза Гэбриэл ушёл из группы. Никто не знал, что Genesis станет ещё успешнее с Коллинзом."]),
        .init(artist: "yes", album: "close to the edge", texts: ["Прог-рок в чистом виде. Три трека, один — на всю сторону.", "Запись была настолько изнурительной, что барабанщик Билл Брюфорд ушёл из группы сразу после."]),
        .init(artist: "king crimson", album: "in the court of the crimson king", texts: ["С обложкой, которую не забыть. Прог-рок начался отсюда.", "Создатель обложки Барри Годбер умер от сердечного приступа через год после выхода альбома. Ему было 24."]),
        .init(artist: "frank zappa", album: "hot rats", texts: ["Преимущественно инструментальный. Заппа здесь — гитарист и композитор, не сатирик.", "На «Willie the Pimp» поёт Капитан Бифхарт — школьный друг Заппы."]),
        .init(artist: "patti smith", album: "horses", texts: ["«Jesus died for somebody's sins but not mine». Первый трек, первая строка.", "Обложка работы Роберта Мэпплторпа стала одной из самых узнаваемых в рок-фотографии."]),
        .init(artist: "the ramones", album: "ramones", texts: ["Дебют. 14 треков за 29 минут. Все одинаковые. И прекрасные.", "Альбом записан за неделю и стоил $6400. Дешевле, чем плита для звукозаписывающей студии того времени."]),
        .init(artist: "sex pistols", album: "never mind the bollocks", texts: ["Единственный студийный альбом Pistols. Этого хватило, чтобы поменять музыку.", "Слово «Bollocks» на обложке пытались запретить британские власти как непристойное. Суд оправдал группу."]),
        .init(artist: "the clash", album: "london calling", texts: ["Двойной альбом. Панк, который перерос панк — рок, рэгги, рокабилли.", "Обложка пародирует первый альбом Элвиса Пресли — буквы те же, шрифт тот же, только разбивают гитару."]),
        .init(artist: "the clash", album: "the clash", texts: ["Дебют. Громче, проще, прямее.", "Альбом записан за три выходных. Звук намеренно сырой — продюсер был против, группа настояла."]),
        .init(artist: "wire", album: "pink flag", texts: ["21 трек за 35 минут. Минималистичный панк. Альбом, который копировали 30 лет.", "Многие треки длятся меньше минуты. Wire считали, что если идея сказана — нечего её повторять."]),
        .init(artist: "television", album: "marquee moon", texts: ["Заглавный трек — 10 минут, и каждая нота на месте. Из Нью-Йорка, но не панк.", "Том Верлен и Ричард Ллойд играли соло, переплетающиеся как разговор. Дуэт гитар, которому не было равных."]),
        .init(artist: "joy division", album: "unknown pleasures", texts: ["Обложка с пульсаром — самый растиражированный графический мотив в музыке.", "Альбом записан за пять дней. Звукоинженер Мартин Хеннетт убрал из звука всё, что мог — оставил только суть."]),
        .init(artist: "joy division", album: "closer", texts: ["Записан незадолго до самоубийства Иэна Кёртиса. Холодный, медленный, неизбежный.", "Группа узнала о смерти Кёртиса, когда альбом уже был готов к печати. Изменить ничего не успели."]),
        .init(artist: "the smiths", album: "the queen is dead", texts: ["Моррисси и Марр в зените. Английский пост-панк-поп с цитатами на каждый случай.", "Заглавный трек открывает альбом 7-минутной репликой королевы из фильма — это «There Is a Light That Never Goes Out»."]),
        .init(artist: "the smiths", album: "the smiths", texts: ["Дебют. Гитары Джонни Марра уже здесь во всей сложности.", "Группа записала альбом дважды — первая версия была отклонена лейблом как слишком сырая."]),
        .init(artist: "new order", album: "power, corruption & lies", texts: ["Joy Division без Кёртиса перешли на синтезаторы и танцпол.", "Обложка работы Питера Сэвилла — репродукция картины Анри Фантен-Латура XIX века. Без указания группы и названия."]),
        .init(artist: "the cure", album: "disintegration", texts: ["Двойной альбом-погружение. Депрессивный, длинный, любимый.", "Роберт Смит сделал альбом перед своим 30-летием, в депрессии. Лейбл считал, что это карьерное самоубийство."]),
        .init(artist: "bauhaus", album: "in the flat field", texts: ["Готик-рок начался здесь.", "Группа записала «Bela Lugosi's Dead» одним дублем за 6 минут. Песня длится 9 — её просто продолжали играть."]),
        .init(artist: "siouxsie and the banshees", album: "juju", texts: ["Сьюзи на пике мрачной готики.", "Группа начала как фанаты Sex Pistols, бывшие в первом ряду на их концертах. Сами научились играть позже."]),
        .init(artist: "killing joke", album: "killing joke", texts: ["Альбом, без которого не было бы Nirvana и Metallica. По их собственному признанию.", "Курт Кобейн использовал басовую линию из их песни «Eighties» в «Come as You Are»."]),
        .init(artist: "public image ltd", album: "metal box", texts: ["Джонни Лайдон после Sex Pistols — холодный, дискомфортный, гениальный.", "Первое издание шло в металлической коробке как у плёнки. Дорого для лейбла, культово для фанатов."]),
        .init(artist: "talking heads", album: "remain in light", texts: ["Записан с Брайаном Ино. Африканские ритмы встретились с нью-йоркским артом.", "Группа записала фундаментальные грувы коллективной импровизацией, потом Бирн добавил тексты."]),
        .init(artist: "talking heads", album: "speaking in tongues", texts: ["«Burning Down the House» — большой хит. Альбом — переходный к танцполу.", "На обложке первого издания — лицо Бирна на просвечивающем виниле. Очень дорого, очень редко."]),
        .init(artist: "devo", album: "q: are we not men? a: we are devo!", texts: ["Странный, синтезаторный, в красных шлемах. Тоже Брайан Ино.", "Группа исповедовала «теорию де-эволюции» — что человечество движется не вперёд, а назад."]),
        .init(artist: "pixies", album: "doolittle", texts: ["Кобейн признавался, что копировал именно их структуру тихо-громко.", "Альбом продюсировал Гил Нортон. Стив Альбини, продюсер их дебюта, был категорически против — слишком чистый звук."]),
        .init(artist: "wu-tang clan", album: "enter the wu-tang (36 chambers)", texts: ["Звучит, как будто записано в подвале. Это и есть подвал. И это великолепно.", "9 человек подписали контракт с лейблом, но оставили за собой право выпускать сольные альбомы. Беспрецедентная сделка."]),
        .init(artist: "nas", album: "illmatic", texts: ["39 минут. 10 треков. Каждый — шедевр. Дебют 20-летнего парня из Квинса.", "На альбоме продюсировали DJ Premier, Pete Rock, Q-Tip, Large Professor — золотой век продюсирования в одном проекте."]),
        .init(artist: "the notorious b.i.g.", album: "ready to die", texts: ["Дебют Бигги. Восточное побережье в высшей точке.", "Через три года после выхода Бигги был застрелен в Лос-Анджелесе. Ему было 24."]),
        .init(artist: "2pac", album: "all eyez on me", texts: ["Двойной альбом. За год до его смерти.", "Первый двойной хип-хоп альбом в истории. Записан за две недели после выхода Тупака из тюрьмы."]),
        .init(artist: "dr. dre", album: "the chronic", texts: ["G-funk родился здесь. Снуп Догг дебютировал отсюда.", "Альбом записан в подвале студии Death Row. Снуп тогда числился рэпером без контракта."]),
        .init(artist: "snoop dogg", album: "doggystyle", texts: ["Дебют. Продолжение «The Chronic».", "Альбом достиг #1 в Billboard сразу после выхода — первый дебютный альбом в истории, который сделал это."]),
        .init(artist: "a tribe called quest", album: "the low end theory", texts: ["Хип-хоп, который пожал руку джазу. Слушается до сих пор.", "На альбоме играет Рон Картер — легендарный джазовый контрабасист, игравший с Майлзом Дэвисом."]),
        .init(artist: "de la soul", album: "3 feet high and rising", texts: ["Хип-хоп до того, как стал серьёзным. Цветной, лёгкий, открытый.", "Group использовала тысячи сэмплов без очистки. Их потом судили — победил истец, лейбл выплатил миллионы."]),
        .init(artist: "public enemy", album: "it takes a nation of millions to hold us back", texts: ["Самый громкий, самый политический хип-хоп-альбом эпохи.", "The Bomb Squad — продюсерская команда альбома — наслаивала по 100-200 сэмплов в одном треке."]),
        .init(artist: "n.w.a", album: "straight outta compton", texts: ["Гангста-рэп родился здесь.", "ФБР отправило лейблу письмо с угрозой за песню «Fuck Tha Police». Группа использовала это для пиара."]),
        .init(artist: "eric b. & rakim", album: "paid in full", texts: ["Рэйким изобрёл многосложную рифмовку. До него такого не было.", "До Рэйкима рэп был ритмическим — «там-та-там-там». Он принёс плотную поэзию."]),
        .init(artist: "run-d.m.c.", album: "raising hell", texts: ["«Walk This Way» с Aerosmith. Хип-хоп вышел в мейнстрим.", "Сотрудничество с Aerosmith организовал Rick Rubin. Aerosmith были в творческом кризисе — он спас их карьеру."]),
        .init(artist: "beastie boys", album: "paul's boutique", texts: ["Альбом из тысячи сэмплов. Сейчас такой нельзя было бы выпустить — лицензии съели бы бюджет.", "Альбом продюсировали The Dust Brothers. Их подход — «звуковой коллаж» — повлиял на всё дальнейшее."]),
        .init(artist: "beastie boys", album: "licensed to ill", texts: ["Дебют. «Fight for Your Right» — первый рэп-хит белых ребят.", "Первый рэп-альбом, достигший #1 в Billboard. Сейчас группа стыдится части текстов с этого альбома."]),
        .init(artist: "outkast", album: "aquemini", texts: ["Южный хип-хоп с шизофренической амбицией.", "Названо в честь зодиаков членов группы — Andre 3000 (Водолей) и Big Boi (Близнецы)."]),
        .init(artist: "outkast", album: "stankonia", texts: ["«B.O.B.» открывает альбом со скоростью 155 BPM. Хип-хоп так быстро никто не делал.", "Стэнкония — название студии группы в Атланте. Они там работали без сна неделями."]),
        .init(artist: "jay-z", album: "the blueprint", texts: ["Канье Уэст продюсировал треки. Выпущен 11 сентября 2001 года.", "В день выхода террористы атаковали Нью-Йорк. Альбом всё равно вышел на #1."]),
        .init(artist: "kanye west", album: "the college dropout", texts: ["Канье как продюсер был известен. Как рэпер — нет. Этот альбом всё изменил.", "Канье попал в страшную аварию незадолго до записи. Записал «Through the Wire» с проволокой в челюсти."]),
        .init(artist: "kanye west", album: "my beautiful dark twisted fantasy", texts: ["Самый амбициозный хип-хоп-альбом 2010-х.", "Канье снял дом на Гавайях и собрал десятки музыкантов и продюсеров. Запись напоминала художественную резиденцию."]),
        .init(artist: "kendrick lamar", album: "good kid, m.a.a.d city", texts: ["Кинематографичный альбом про взросление в Комптоне.", "Альбом задуман как фильм — каждый трек как сцена, между ними — голосовые сообщения от мамы Кендрика."]),
        .init(artist: "kendrick lamar", album: "to pimp a butterfly", texts: ["Джаз, фанк, политика. Один из главных альбомов десятилетия.", "Президент Обама пригласил Кендрика в Белый дом обсудить «To Pimp a Butterfly». Беспрецедентно для рэпера."]),
        .init(artist: "j dilla", album: "donuts", texts: ["Инструментальный хип-хоп. Записан Дилле в больнице, за три дня до его смерти.", "31 трек по 1-2 минуты — как короткие виньетки. Дилла знал, что умирает, и торопился."]),
        .init(artist: "madvillain", album: "madvillainy", texts: ["MF DOOM и Madlib. Альбом без хуков, без хитов, но с культовым статусом.", "Утечка альбома произошла за год до релиза. Madlib и DOOM перезаписали половину после утечки."]),
        .init(artist: "mos def", album: "black on both sides", texts: ["Сейчас он Yasiin Bey. Тогда — Mos Def с одним из самых поэтичных хип-хоп альбомов.", "Mos Def — формальный поэт. Учился ремеслу у поэтов Last Poets и Гила Скотта-Херона."]),
        .init(artist: "the roots", album: "things fall apart", texts: ["Хип-хоп с живой группой. Долгий, медленный, аналоговый.", "Это был первый альбом The Roots, который продался золотым тиражом. Группа существовала уже 12 лет."]),
        .init(artist: "aretha franklin", album: "i never loved a man the way i love you", texts: ["Запись в Muscle Shoals, легендарная сессия. Арета стала Аретой здесь.", "Сессия завершилась дракой. Альбом дозаписывался в Нью-Йорке без южной ритм-секции."]),
        .init(artist: "otis redding", album: "otis blue", texts: ["Записан за 24 часа подряд. Хит за хитом.", "Альбом включает кавер «Satisfaction» Rolling Stones — Реддинг записал её, не зная слов до конца, импровизируя."]),
        .init(artist: "ray charles", album: "the genius of ray charles", texts: ["Здесь Чарльз соединил соул с биг-бэндом. Никто до него так не делал.", "Альбом записан с двумя оркестрами — Quincy Jones аранжировал джазовую сторону."]),
        .init(artist: "sam cooke", album: "live at the harlem square club", texts: ["Кук был «королём соула». Эта концертная запись — самая горячая.", "Альбом не выпускали 22 года. RCA считала, что «грубый» Кук на этой записи испортит его поп-имидж."]),
        .init(artist: "james brown", album: "live at the apollo", texts: ["Концертный альбом. Записан с третьей попытки.", "Брауну пришлось оплатить запись из своего кармана — лейбл считал концертный соул-альбом рискованным."]),
        .init(artist: "curtis mayfield", album: "super fly", texts: ["Саундтрек к фильму, который оказался лучше фильма. Социальный фанк.", "Mayfield писал тексты как комментарий к сюжету фильма — критиковал героиновый бизнес, тогда как фильм его прославлял."]),
        .init(artist: "stevie wonder", album: "talking book", texts: ["«Superstition». Стиви начинает свою главную серию альбомов 70-х.", "Заглавный сингл «Superstition» Стиви изначально написал для Джеффа Бека, но потом решил оставить себе."]),
        .init(artist: "sly and the family stone", album: "there's a riot goin' on", texts: ["Тёмный, наркотический, гениальный. Через два года после оптимистичного «Stand!».", "Sly Stone записывал альбом в одиночку, многократно записывая и стирая собственные дубли. Получилось мутно и гениально."]),
        .init(artist: "funkadelic", album: "maggot brain", texts: ["Заглавный трек — 10 минут гитарного соло Эдди Хэйзела.", "Хэйзел играл это соло один дубль. Джордж Клинтон сказал ему: «играй так, будто твоя мать только что умерла»."]),
        .init(artist: "parliament", album: "mothership connection", texts: ["П-Фанк во всей мощи. Космический фанк.", "На концертах Parliament из «материнского корабля» спускался на сцену настоящий 3-тонный корабль. Шоу стоило целое состояние."]),
        .init(artist: "earth, wind & fire", album: "that's the way of the world", texts: ["Эпохальный соул-фанк-альбом. «Shining Star», «Reasons».", "Альбом был саундтреком к фильму, который провалился. Альбом — нет."]),
        .init(artist: "al green", album: "call me", texts: ["Сладкий мемфисский соул. Эл Грин в безупречной форме.", "Грин записывал у Уилли Митчелла в Royal Studios — деревянная комната, которой более 100 лет."]),
        .init(artist: "donny hathaway", album: "live", texts: ["Один из лучших концертных альбомов в истории соула.", "Хэтуэй страдал от шизофрении и покончил с собой в 33 года, выпрыгнув из окна нью-йоркского отеля."]),
        .init(artist: "d'angelo", album: "voodoo", texts: ["Нео-соул в его зените. Запись с The Roots и Q-Tip.", "D'Angelo пропал после релиза на 14 лет — стал затворником, проиграл в весе и наркомании."]),
        .init(artist: "d'angelo", album: "black messiah", texts: ["14 лет после Voodoo. Слушается, как будто и не было паузы.", "Альбом выпустили на месяц раньше плана из-за событий в Фергюсоне — он стал саундтреком к движению Black Lives Matter."]),
        .init(artist: "erykah badu", album: "mama's gun", texts: ["Эрика Баду на пике своего нео-соула.", "Альбом начинается с 8-минутного трека «Penitentiary Philosophy» — никаких уступок поп-формату."]),
        .init(artist: "lauryn hill", album: "the miseducation of lauryn hill", texts: ["Единственный её студийный альбом. Безупречный.", "Альбом получил 5 «Грэмми» — рекорд для женщины-исполнителя на тот момент."]),
        .init(artist: "frank ocean", album: "channel orange", texts: ["Современный соул в самой утончённой форме.", "За неделю до релиза Оушен написал в блоге об отношениях с мужчиной. Первый такой жест в хип-хоп/соул среде."]),
        .init(artist: "frank ocean", album: "blonde", texts: ["Альбом, который Ocean делал в одиночку. Минималистичный, разрозненный, любимый.", "Альбом вышел через 4 года после Channel Orange. Все эти годы Оушен молчал — даже о факте работы."]),
        .init(artist: "solange", album: "a seat at the table", texts: ["Сестра Бейонсе сделала свой шедевр. Соул для современной эпохи.", "Альбом был записан в Луизиане — Solange вернулась к корням семьи, чтобы записать его."]),
        .init(artist: "kraftwerk", album: "trans-europe express", texts: ["Немецкие пионеры синтезаторной музыки. Без них не было бы ни хип-хопа, ни техно.", "«Trans-Europe Express» был сэмплирован в «Planet Rock» Африка Бамбата — основополагающем хип-хоп-треке."]),
        .init(artist: "kraftwerk", album: "computer world", texts: ["Альбом про эпоху, которая ещё не наступила. Сейчас он звучит как пророчество.", "Группа писала про данные, экраны, банкоматы — за десятилетие до того, как это стало реальностью."]),
        .init(artist: "brian eno", album: "music for airports", texts: ["Эмбиент как жанр официально начался здесь.", "Эно действительно хотел, чтобы эту музыку играли в аэропортах. В одном американском аэропорту её крутили несколько месяцев."]),
        .init(artist: "brian eno", album: "another green world", texts: ["Полу-песни, полу-инструменталки. Альбом-сад.", "Эно сочинял на ходу, используя свои «косые карточки» — карточки с непонятными инструкциями для музыкантов."]),
        .init(artist: "tangerine dream", album: "phaedra", texts: ["Берлинская школа электроники. Длинные, медленные путешествия.", "Альбом записан на студии Virgin в Англии, в первые недели существования лейбла Брэнсона."]),
        .init(artist: "aphex twin", album: "selected ambient works 85-92", texts: ["Сборник домашних записей, ставший классикой.", "Ричард Джеймс утверждал, что записал часть этих треков в 14 лет. Никто не смог это ни подтвердить, ни опровергнуть."]),
        .init(artist: "aphex twin", album: "richard d. james album", texts: ["Параноидальный, скоростной, человечный.", "Обложка — собственное лицо Ричарда Джеймса. До этого его никто не видел публично много лет."]),
        .init(artist: "boards of canada", album: "music has the right to children", texts: ["Ностальгия по детству, которого не было. Эстетика 70-х видеозаписей.", "Группа намеренно использовала старые синтезаторы и плёночные кассеты, чтобы получить «выцветший» звук."]),
        .init(artist: "daft punk", album: "discovery", texts: ["Французский дом во всей пышности. «One More Time», «Harder, Better, Faster, Stronger».", "Альбом был использован как саундтрек к аниме «Интерстелла 5555» — режиссёром выступил Leiji Matsumoto."]),
        .init(artist: "daft punk", album: "random access memories", texts: ["Возвращение к живым инструментам. С Нилом Роджерсом, Джорджо Мородером.", "Дуэт продал больше пластинок с этим альбомом, чем со всеми предыдущими вместе взятыми."]),
        .init(artist: "the chemical brothers", album: "dig your own hole", texts: ["Биг-бит на пике. Танцпол + рок-агрессия.", "На «Setting Sun» поёт Ноэл Галлахер из Oasis. Сингл стал номером 1 в Британии."]),
        .init(artist: "massive attack", album: "mezzanine", texts: ["Триждать-эстетика в чёрном цвете. Бристольский саунд.", "Альбом записан настолько долго и тяжело, что состав группы развалился. Большинство альбома записали только два участника."]),
        .init(artist: "massive attack", album: "blue lines", texts: ["Первый трип-хоп-альбом. До этого жанра не существовало.", "На альбоме поёт Шара Нельсон — её карьера началась здесь. Также — Тришка, тогда ещё не Tricky."]),
        .init(artist: "portishead", album: "dummy", texts: ["Бристоль, тяжёлый бит, голос Бэт Гиббонс. Триждать как жанр.", "Группа выпускает альбомы крайне редко — за 30 лет только три. Их «Dummy» получил Mercury Prize."]),
        .init(artist: "burial", album: "untrue", texts: ["Дабстеп до того, как стал брокор. Тихий, городской, ночной.", "Burial — псевдоним Уильяма Бевана. До 2008 года его личность была неизвестна — он был «лондонским тайным городским дабстеп-композитором»."]),
        .init(artist: "caribou", album: "swim", texts: ["Танцевальная электроника, сделанная музыкантом-математиком.", "Дэн Снейт (Caribou) имеет докторскую степень по математике от Имперского колледжа."]),
        .init(artist: "lcd soundsystem", album: "sound of silver", texts: ["Танцпунк со средним возрастом и иронией.", "Джеймс Мерфи начал группу в 33 — поздно для танцевальной музыки. Это и стало его темой."]),
        .init(artist: "four tet", album: "rounds", texts: ["Folktronica. Электроника, звучащая как живая.", "Кирен Хебден (Four Tet) сэмплирует свои собственные акустические записи — гитары, флейты, бубны."]),
        .init(artist: "autechre", album: "tri repetae", texts: ["IDM в чистом виде. Сложно, абстрактно, требует внимания.", "Альбом записан полностью на ранних драм-машинах и сэмплерах. Никаких компьютерных программ."]),
        .init(artist: "underworld", album: "dubnobasswithmyheadman", texts: ["Прогрессив-хаус с поэзией.", "Эта пластинка переломила восприятие электронной музыки — впервые альбом дэнс-музыки слушали целиком, не для танцпола."]),
        .init(artist: "nirvana", album: "nevermind", texts: ["Альбом, который убил глэм-метал и принёс гранж в мейнстрим.", "Бутч Виг сделал звук альбома неожиданно чистым. Кобейн позже жалел — хотел сырого звука."]),
        .init(artist: "nirvana", album: "in utero", texts: ["После «Nevermind». Грубее, сырее. Кобейн хотел уйти от чистого звука Бутча Вига.", "Альбом продюсировал Стив Альбини. Он сделал его за две недели, без эффектов, без полировки."]),
        .init(artist: "pearl jam", album: "ten", texts: ["Дебют. Главный альбом гранжа, помимо «Nevermind».", "Альбом стоял в Billboard 200 в течение 5 лет — невероятная стойкость для дебюта."]),
        .init(artist: "soundgarden", album: "superunknown", texts: ["«Black Hole Sun». Гранж с прог-роковой амбицией.", "Альбом дошёл до #1 в Billboard в первую же неделю — необычно для тяжёлого жанра в 1994."]),
        .init(artist: "alice in chains", album: "dirt", texts: ["Самый тёмный гранж-альбом. Стэйли поёт о наркотиках с ужасом изнутри.", "Стэйли умер от передозировки в 2002. Многие тексты альбома оказались автопророчествами."]),
        .init(artist: "radiohead", album: "ok computer", texts: ["Альбом про будущее, написанный в 1997 году. Сейчас он звучит ещё актуальнее.", "Альбом записан в особняке актрисы Джейн Сеймур в Англии. Группа жила там три месяца."]),
        .init(artist: "radiohead", album: "kid a", texts: ["Радиохед взорвали свой звук и пересобрали с нуля. Электроника, ноль гитарных хитов.", "Альбом не имел синглов и почти не имел маркетинговой кампании. Всё равно стал #1."]),
        .init(artist: "radiohead", album: "in rainbows", texts: ["Группа выложила альбом «плати сколько хочешь». Революция в дистрибуции.", "В среднем люди платили $6 за альбом. Радиохэду это принесло больше денег, чем все их предыдущие альбомы вместе."]),
        .init(artist: "radiohead", album: "the bends", texts: ["До OK Computer. Альбом, которым они доказали, что они не «Creep».", "Йорк сорвал голос на гастролях после «Pablo Honey». «The Bends» он записал, восстанавливаясь."]),
        .init(artist: "r.e.m.", album: "automatic for the people", texts: ["«Everybody Hurts», «Man on the Moon». Самый меланхоличный их альбом.", "Название взято из лозунга кафе в родном городе группы Афинс, Джорджия. Кафе до сих пор работает."]),
        .init(artist: "r.e.m.", album: "murmur", texts: ["Дебют. Бормотание Майкла Стайпа стало эстетикой.", "Тексты Стайпа на ранних альбомах принципиально неразборчивы — он сам так хотел."]),
        .init(artist: "the pixies", album: "surfer rosa", texts: ["До «Doolittle». Грубее, страннее. Записан Стивом Альбини.", "Альбом был хитом в Британии, но почти никем не услышан в Америке. Это была судьба Pixies в 80-х."]),
        .init(artist: "my bloody valentine", album: "loveless", texts: ["Стена гитарного шума, под которой — мелодии. Шугейз в высшей точке.", "Запись стоила лейблу Creation $250,000 — невероятная сумма для инди в 1991. Чуть не разорила лейбл."]),
        .init(artist: "sonic youth", album: "daydream nation", texts: ["Двойной альбом. Эксперименты с гитарными настройками превратились в полноценные песни.", "Каждая гитара группы настроена по-своему. Sonic Youth используют десятки «изобретённых» настроек."]),
        .init(artist: "slint", album: "spiderland", texts: ["Пост-рок начался здесь. Тихо, потом громко, потом снова тихо.", "Группа распалась сразу после записи. Барабанщик попал в психиатрическую клинику, остальные ушли в обычную жизнь."]),
        .init(artist: "pavement", album: "slanted and enchanted", texts: ["Лоу-фай как эстетика. Альбом, на котором инди стал инди.", "Стивен Малкмус записывал альбом дома на 4-дорожечный магнитофон. Звук намеренно «дешёвый»."]),
        .init(artist: "beck", album: "odelay", texts: ["Лоу-фай-хип-хоп-фолк-блюз. Бек смешал всё подряд и получилось.", "Альбом продюсировали Dust Brothers — те же, что Beastie Boys «Paul's Boutique». Подход «звуковой коллаж»."]),
        .init(artist: "the strokes", album: "is this it", texts: ["Альбом, который вернул рок-н-ролл в Нью-Йорк в нулевые.", "Британская обложка альбома — фото руки на бедре женщины — была заменена в Америке на абстрактную графику."]),
        .init(artist: "the white stripes", album: "elephant", texts: ["Двое человек, гитара и барабаны. «Seven Nation Army».", "Альбом записан полностью на аналоговое оборудование старше 1963 года. Принципиальная позиция Джека Уайта."]),
        .init(artist: "arcade fire", album: "funeral", texts: ["Канадский инди в эпическом масштабе. Дебют.", "Альбом назвали «Funeral», потому что во время записи в семьях членов группы умерло несколько родственников."]),
        .init(artist: "modest mouse", album: "good news for people who love bad news", texts: ["«Float On» вышел в радио. Альбом — гораздо страннее заглавного хита.", "Группа существовала 10 лет до этого хита, в полной безвестности. «Float On» изменил всё за месяц."]),
        .init(artist: "yeah yeah yeahs", album: "fever to tell", texts: ["Гаражный рок начала 2000-х в женском вокале.", "Карен О пробежала через несколько отелей Нью-Йорка, разбивая свои гостиничные номера в туре. Стала иконой."]),
        .init(artist: "the national", album: "boxer", texts: ["Меланхоличный американский инди для пьющих кофе утром.", "Альбом включён в саундтрек предвыборной кампании Барака Обамы 2008. Группа симпатизировала."]),
        .init(artist: "bon iver", album: "for emma, forever ago", texts: ["Записан в хижине в лесу за одну зиму. После расставания.", "Джастин Вернон записал альбом полностью один, на простую звукозаписывающую установку. Без других людей."]),
        .init(artist: "vampire weekend", album: "vampire weekend", texts: ["Дебют. Африканский гитарный паттерн встретился с гарвардским образованием.", "Группа познакомилась в Колумбийском университете, где все четверо были студентами."]),
        .init(artist: "amy winehouse", album: "back to black", texts: ["Соул в современной упаковке. Винехаус не успела дожить до зрелости — это её зенит.", "Альбом продюсировал Марк Ронсон с группой Dap-Kings — настоящей мемфисской ритм-секцией."]),
        .init(artist: "adele", album: "21", texts: ["Самый продаваемый альбом 2010-х. Не случайно.", "Альбом провёл в Top 5 Billboard 200 более 100 недель — больше, чем любой другой альбом 2010-х."]),
        .init(artist: "arctic monkeys", album: "am", texts: ["Группа выросла из британской инди-сцены в стадион.", "Алекс Тёрнер сменил образ — отрастил волосы, начал петь медленнее. Группа стала звучать «по-голливудски»."]),
        .init(artist: "tame impala", album: "currents", texts: ["Кевин Паркер один сделал главный психоделический поп-альбом десятилетия.", "Паркер играет на каждом инструменте на альбоме. Tame Impala — это, по сути, один человек."]),
        .init(artist: "mac demarco", album: "salad days", texts: ["Слекер-рок 2010-х. Расслабленный, ленивый, обаятельный.", "ДеМарко записывает дома, на простой аппаратуре. Намеренно сохраняет лоу-фай эстетику."]),
        .init(artist: "king krule", album: "the ooz", texts: ["Голос подростка из юго-восточного Лондона, который звучит как взрослый ночной город.", "Арчи Маршалл (King Krule) сменил несколько псевдонимов прежде, чем остановиться на этом."]),
        .init(artist: "fka twigs", album: "lp1", texts: ["Альбом-сон. Электронный авангард с поп-доступностью.", "До музыки FKA Twigs работала танцовщицей в клипах других артистов. Её движения — часть её музыкальной идентичности."]),
        .init(artist: "beach house", album: "bloom", texts: ["Дрим-поп в его самой узнаваемой форме.", "Группа — дуэт из Балтимора. Они записывают почти всё дома, без сторонних продюсеров."]),
        .init(artist: "sufjan stevens", album: "carrie & lowell", texts: ["Альбом про маму, которая умерла. Самый тихий и личный из его работ.", "Кэрри — мать Стивенса, ушедшая из семьи. Лоуэлл — отчим. Альбом — переработка детского опыта потери."]),
        .init(artist: "big thief", album: "two hands", texts: ["Современный американский фолк-рок. Записан вживую, без наложений.", "Big Thief выпустили два альбома в 2019 году — «U.F.O.F.» и «Two Hands». Оба считаются великими."]),
        .init(artist: "bob marley & the wailers", album: "exodus", texts: ["Альбом записан в Лондоне, куда Марли уехал после покушения на Ямайке.", "Журнал Time назвал «Exodus» альбомом века в 1999 году. Спорное решение — но не безосновательное."]),
        .init(artist: "bob marley & the wailers", album: "catch a fire", texts: ["Первый альбом Wailers на международном лейбле. Регги вышел из Ямайки.", "Обложка первого тиража имела форму зажигалки Zippo, открывавшейся вертикально. Дорого и культово."]),
        .init(artist: "burning spear", album: "marcus garvey", texts: ["Регги о Маркусе Гарви — пророке движения растафари.", "Burning Spear был одним из самых философских голосов регги. Альбом — манифест ямайского самосознания."]),
        .init(artist: "lee «scratch» perry & the upsetters", album: "super ape", texts: ["Даб-классика. Perry создал жанр и тут же его переопределил.", "Студия Перри Black Ark сгорела дотла в 1979. Перри утверждал, что сжёг её сам — «изгонял дьявола»."]),
        .init(artist: "augustus pablo", album: "king tubbys meets rockers uptown", texts: ["Pablo на мелодике, King Tubby за пультом. Даб в своей самой возвышенной форме.", "Мелодика — игрушечный инструмент. Pablo сделал из неё голос целого жанра."]),
        .init(artist: "black sabbath", album: "master of reality", texts: ["Третий альбом за два года. Тяжелее предыдущих, плотнее.", "Тони Айомми настроил гитару на полтора тона ниже — из-за травмы пальцев. Это создало звук дума и слюджа на десятилетия вперёд."]),
        .init(artist: "iron maiden", album: "the number of the beast", texts: ["Брюс Дикинсон присоединился к группе. Британский метал получил голос.", "Альбом был объявлен сатанинским в США, но цифры в названии — отсылка к роману Хайнлайна, не к Откровению."]),
        .init(artist: "metallica", album: "master of puppets", texts: ["Трэш-метал в зрелости. Восьмиминутные треки с тысячью гитарных партий.", "Басист Клифф Бертон погиб в автокатастрофе вскоре после релиза. Группа решила продолжать."]),
        .init(artist: "slayer", album: "reign in blood", texts: ["29 минут чистой агрессии. Альбом, который определил жанр.", "Альбом был отвергнут Columbia Records из-за текстов про Йозефа Менгеле. Вышел на Def Jam — лейбле хип-хопа."]),
        .init(artist: "robert johnson", album: "king of the delta blues singers", texts: ["Сборник записей блюзмена, умершего в 1938 году. Все его треки — на одной пластинке.", "Легенда гласит, что Джонсон продал душу дьяволу за умение играть на гитаре. Историки этому подвержены сомнению."]),
        .init(artist: "muddy waters", album: "folk singer", texts: ["Электрический блюз-гигант записал акустический альбом. Странное решение, гениальный результат.", "Альбом задумывали как «для фолк-публики», которая тогда не воспринимала электрический блюз."]),
        .init(artist: "b.b. king", album: "live at the regal", texts: ["Концертный альбом, который объяснил остальному миру, что такое блюз.", "Эта запись стала учебником для Эрика Клэптона, Майка Блумфилда, Стиви Рэя Вогана."]),
        .init(artist: "johnny cash", album: "at folsom prison", texts: ["Кэш выступил в тюрьме Фолсом. Запись стала классикой.", "Кэш специально вставил в плейлист песни про убийства и заключение. Заключённые встретили его как своего."]),
        .init(artist: "willie nelson", album: "red headed stranger", texts: ["Концептуальный кантри-альбом про беглого священника. Аскетичный, минималистичный.", "Лейбл хотел отказаться выпускать — слишком странно. Альбом стал одним из самых продаваемых в кантри-истории."]),
        .init(artist: "patsy cline", album: "sentimentally yours", texts: ["Голос, который определил женский кантри. Заглавный трек — стандарт жанра.", "Кляйн погибла в авиакатастрофе через год после релиза. Ей было 30."]),
        .init(artist: "brian eno", album: "ambient 1: music for airports", texts: ["Эно изобрёл эмбиент как жанр. Этот альбом — манифест.", "Эно дал каждой стороне название «1/1», «2/1» и т. д. — намеренно не называя треки именами."]),
        .init(artist: "aphex twin", album: "selected ambient works volume ii", texts: ["Все треки без названий. Эмбиент в самой холодной форме.", "Каждая обложка маленьких изображений — это идея конкретного трека. Ричард Джеймс ассоциировал звуки с картинками."]),
        .init(artist: "stars of the lid", album: "the tired sounds of stars of the lid", texts: ["Двойной альбом эмбиента. Долгий, медитативный, бесконечный.", "Группа состоит из двух человек, живущих на разных континентах. Они обмениваются файлами по почте."]),
        .init(artist: "can", album: "tago mago", texts: ["Краут-рок в полноте. Двойной альбом, на котором группа открыла «motorik» — гипнотический ритм.", "Дамо Сузуки, японский певец Can, был «найден» уличным музыкантом в Мюнхене. Стал голосом группы."]),
        .init(artist: "neu!", album: "neu!", texts: ["Дебют дуэта из Дюссельдорфа. Изобрели motorik beat — прямой, постоянный ритм.", "Без Neu! не было бы пост-панка, инди-рока, синтпопа. Они повлияли на всех."]),
        .init(artist: "faust", album: "faust", texts: ["Дебют немецкого авангардистов. Альбом записан в переоборудованной школе.", "Лейбл Polydor выпустил альбом в прозрачной обёртке — внутри был прозрачный винил."]),
        .init(artist: "kraftwerk", album: "autobahn", texts: ["Первый коммерческий успех Kraftwerk. 22-минутный заглавный трек о немецкой автостраде.", "Сокращённая версия трека стала хитом в США. Никто не знал, что слушает революцию."]),
        .init(artist: "cluster", album: "zuckerzeit", texts: ["Тёплый, мелодичный электронный альбом. Между авангардом и поп-музыкой.", "Cluster позже записали два альбома совместно с Брайаном Ино. Те альбомы — ключевые для понимания эмбиента."]),
        .init(artist: "john coltrane", album: "ascension", texts: ["Фри-джазовый эпос. 40 минут коллективной импровизации с 11 музыкантами.", "Альбом был выпущен в двух версиях — Edition I и Edition II — с разными мастерингами. Никто не знает почему."]),
        .init(artist: "albert ayler", album: "spiritual unity", texts: ["Фри-джаз в самой радикальной форме. Айлер играл так, как никто до и после.", "Айлер был найден мёртвым в Ист-Ривере в 1970 году. Обстоятельства его смерти неясны до сих пор."]),
        .init(artist: "fela kuti", album: "zombie", texts: ["Afrobeat достиг политической остроты. Альбом критикует нигерийскую военную диктатуру.", "Через год после релиза военные сожгли дом Кути и убили его мать. Сам он провёл много лет в тюрьме."]),
        .init(artist: "tinariwen", album: "aman iman: water is life", texts: ["Туареги Сахары играют гитарный рок. Уникальный голос пустыни.", "Группа состоит из бывших солдат повстанческой армии. Их музыка — голос целого народа."]),
        .init(artist: "mulatu astatke", album: "ethio-jazz", texts: ["Эфиопский джаз — отдельный жанр, придуманный одним человеком.", "Астатке учился музыке в Лондоне и Бостоне, потом вернулся в Эфиопию и создал жанр почти в одиночку."]),
        .init(artist: "caetano veloso", album: "caetano veloso", texts: ["Бразильская tropicalia в дебютном альбоме. Революция в латинской музыке.", "Через год после релиза Велозу был арестован военной хунтой и выслан из Бразилии."]),
        .init(artist: "os mutantes", album: "os mutantes", texts: ["Бразильский психоделический рок. Странный, цветной, новаторский.", "Группа стала культовой через 30 лет после распада. Курт Кобейн пытался их воссоединить — не успел."]),
        .init(artist: "john cage", album: "imaginary landscape no. 4", texts: ["Композиция для 12 радиоприёмников. Случайность как метод сочинения.", "Кейдж установил частоты и громкость, но содержание зависело от того, что транслировали в момент исполнения."]),
        .init(artist: "steve reich", album: "music for 18 musicians", texts: ["Минимализм в его самой богатой форме. 55 минут пульсирующего звука.", "Альбом записан с одного дубля. Музыканты репетировали год, прежде чем приступить к записи."]),
        .init(artist: "terry riley", album: "a rainbow in curved air", texts: ["Электронный минимализм до того, как стал жанром. Альбом из двух длинных треков.", "Альбом повлиял на Кейрел, Pink Floyd, краут-рок. Райли работал в одиночку, импровизируя в реальном времени."]),
        .init(artist: "philip glass", album: "glassworks", texts: ["Минимализм для широкой аудитории. Восемь коротких пьес.", "Гласс продюсировал альбом сам и записал на свой лейбл, потому что классические лейблы отказывались."]),
        .init(artist: "la monte young", album: "the well-tuned piano", texts: ["Дронам музыка на 5-часовом фортепианном произведении. Самое длинное классическое сочинение в истории.", "Янг работал над пьесой 30 лет до этой записи. Каждое исполнение длилось пять часов."]),
        .init(artist: "throbbing gristle", album: "20 jazz funk greats", texts: ["Альбом, который выглядит как лёгкая поп-музыка, а звучит как индустриальный кошмар.", "Обложка с фотографией группы на солнечном склоне холма — сознательная ирония. Холм этот — известное место самоубийств в Англии."]),
        .init(artist: "coil", album: "horse rotorvator", texts: ["Индустриал с уклоном в оккультизм. Один из самых сложных альбомов жанра.", "Группа состояла из двух человек, бывших партнёров в жизни. Их работа неразделима от их отношений."]),
        .init(artist: "whitehouse", album: "bird seed", texts: ["Power electronics в чистом виде. Шум как форма музыки.", "Альбом записан как «терапия» — участники группы пытались физически выразить психологическую агрессию."]),
        .init(artist: "merzbow", album: "pulse demon", texts: ["Японский ноиз во всей своей физической силе.", "Merzbow — один человек, Масами Акита, выпустил более 400 альбомов. «Pulse Demon» считается самым доступным."]),
        .init(artist: "sufjan stevens", album: "illinois", texts: ["Концептуальный альбом про штат Иллинойс. Стивенс планировал сделать альбом про каждый штат — отказался после второго.", "На альбоме 22 трека, более 70 минут. Стивенс играет на десятках инструментов."]),
        .init(artist: "sigur rós", album: "ágætis byrjun", texts: ["Исландский пост-рок. Альбом, который привлёк мировое внимание к малой северной стране.", "Йонси Биркьюр (вокалист) поёт на смеси исландского и придуманного языка «Hopelandic»."]),
        .init(artist: "godspeed you! black emperor", album: "lift your skinny fists like antennas to heaven", texts: ["Двойной альбом пост-рока. Четыре эпических трека, каждый длится более 20 минут.", "Группа никогда не даёт интервью. Их музыка — единственный язык, на котором они общаются с миром."]),
        .init(artist: "mogwai", album: "young team", texts: ["Шотландский пост-рок. Альбом, на котором жанр получил форму.", "Группа известна тем, что играет музыку без слов — но называет треки фразами, которые мог бы петь вокалист."]),
        .init(artist: "tortoise", album: "tnt", texts: ["Чикагский пост-рок. Джаз, электроника, рок — слились в один жанр.", "Tortoise состоит из музыкантов, которые играют в десятке других проектов. «TNT» — их вершина."]),
        .init(artist: "slowdive", album: "souvlaki", texts: ["Шугейз во второй волне. Альбом, который провалился в 1993, переоткрыт в 2010-х.", "Slowdive распались сразу после альбома, испытывая разочарование. Воссоединились через 20 лет."]),
        .init(artist: "cocteau twins", album: "heaven or las vegas", texts: ["Дрим-поп в самой узнаваемой форме. Голос Лиз Фрейзер — отдельный инструмент.", "Лиз Фрейзер поёт фактически на придуманном языке. Слова неразборчивы намеренно."]),
        .init(artist: "the jesus and mary chain", album: "psychocandy", texts: ["Поп-песни, утопленные в гитарном фидбэке. Альбом, изобретший шугейз.", "Концерты группы длились по 20 минут. Они играли так громко и так агрессивно, что часто слушатели уходили."]),
        .init(artist: "my bloody valentine", album: "isn't anything", texts: ["До Loveless. Дебютный альбом, на котором группа уже придумала свой звук.", "Альбом записан за 3 недели. Loveless — за 2 года и 19 студий."]),
        .init(artist: "the stone roses", album: "the stone roses", texts: ["Манчестерский «мэдчестер» в дебютном альбоме. Соединил рок с танцполом.", "Группа судилась с лейблом столько, что не выпускала альбома 5 лет. Когда выпустили «Second Coming» — уже было поздно."]),
        .init(artist: "spiritualized", album: "ladies and gentlemen we are floating in space", texts: ["Альбом-таблетка. Первый тираж был выпущен в форме блистера для лекарств.", "Джейсон Пирс написал альбом после расставания с многолетней партнёршей. Альбом — обряд прощания."]),
        .init(artist: "michael jackson", album: "thriller", texts: ["Самый продаваемый альбом в истории. Около 70 миллионов копий.", "Винсент Прайс записал монолог в финале заглавного трека за один дубль. Quincy Jones заплатил ему $20,000."]),
        .init(artist: "michael jackson", album: "off the wall", texts: ["До «Thriller». Quincy Jones как продюсер на пике формы.", "Джексону был 21 год. Альбом ознаменовал его переход из подросткового артиста во взрослого."]),
        .init(artist: "prince", album: "purple rain", texts: ["Соулдрак к фильму, который оказался саундтреком к десятилетию.", "Принс играет на всех инструментах в большинстве треков. Группа The Revolution участвует только в нескольких."]),
        .init(artist: "prince", album: "sign o' the times", texts: ["Двойной альбом. Принс на абсолютной творческой вершине.", "Записан как соло-проект после распада The Revolution. Принс игнорировал предложения лейбла сделать его сольным."]),
        .init(artist: "madonna", album: "like a prayer", texts: ["Самый смелый альбом Мадонны. Религия, секс, политика — всё на одной пластинке.", "Pepsi заплатила Мадонне $5 миллионов за рекламу с песней, потом отменила сотрудничество после выхода клипа."]),
        .init(artist: "whitney houston", album: "whitney houston", texts: ["Дебют. Альбом, провозгласивший новую королеву поп-музыки.", "Альбом провёл 14 недель на #1 Billboard — рекорд для дебюта женщины-артиста."]),
        .init(artist: "the police", album: "synchronicity", texts: ["Последний альбом The Police. На пике коммерческого успеха.", "Группа распалась после тура. «Every Breath You Take» стала самым проигрываемым треком в истории радио."]),
        .init(artist: "phil collins", album: "face value", texts: ["Сольный дебют барабанщика Genesis. «In the Air Tonight» отсюда.", "Барабанный брейк в «In the Air Tonight» — один из самых сэмплированных в истории."]),
        .init(artist: "peter gabriel", album: "so", texts: ["Сольный успех бывшего вокалиста Genesis. «Sledgehammer», «Don't Give Up».", "Клип «Sledgehammer» — самый награждаемый клип в истории MTV Video Music Awards."]),
        .init(artist: "kate bush", album: "hounds of love", texts: ["Концептуальный альбом с двумя сторонами разной природы. Сторона B — «The Ninth Wave», сюита из 7 песен.", "Кейт Буш записывала альбом в своей домашней студии. Контролировала всё — продюсирование, аранжировки, исполнение."]),
        .init(artist: "björk", album: "homogenic", texts: ["Электронный альбом. Бьорк ушла от своего бойфренда и переехала в Испанию.", "Каждый трек — личный жест. «Jóga» — посвящение лучшей подруге, «5 Years» — крик расставания."]),
        .init(artist: "carole king", album: "tapestry", texts: ["25 миллионов копий. Альбом-стандарт для авторов-исполнителей.", "Кинг до этого писала хиты для других: Aretha Franklin, The Monkees. «Tapestry» — её отказ оставаться в тени."]),
        .init(artist: "james taylor", album: "sweet baby james", texts: ["Альбом, которым Тейлор стал Тейлором. «Fire and Rain», «Sweet Baby James».", "Заглавная песня посвящена племяннику Тейлора. Альбом — поворот в его карьере после неудачного дебюта."]),
        .init(artist: "cat stevens", album: "tea for the tillerman", texts: ["Альбом-классика «folk-singer-songwriter» эпохи. «Father and Son», «Wild World».", "Стивенс принял ислам в 1977 и сменил имя на Юсуф. Замолчал в музыке на 25 лет."]),
        .init(artist: "carly simon", album: "no secrets", texts: ["Альбом с песней «You're So Vain» — одной из самых ребус-полных в поп-истории.", "До сих пор не известно, о ком песня. Саймон называла несколько имён — никогда не одно и то же."]),
        .init(artist: "lana del rey", album: "born to die", texts: ["Дебют. Тоскливый, кинематографичный поп. Эстетика «Old Hollywood» в современной упаковке.", "Альбом критики разорвали, публика полюбила. Лана Дель Рей стала одной из самых влиятельных артисток 2010-х."]),
        .init(artist: "lana del rey", album: "norman fucking rockwell!", texts: ["Альбом-вершина творчества Дель Рей. Музыкальная критика наконец признала её гением.", "Заглавный трек — критика американского патриархата через призму Рокуэлла, символа Америки 50-х."]),
        .init(artist: "phoebe bridgers", album: "punisher", texts: ["Современный инди-фолк. Альбом про детство, отношения, смерть.", "Бриджерс прославилась во время локдауна 2020. Её хриплый голос и мрачные тексты стали саундтреком эпохи."]),
        .init(artist: "mitski", album: "be the cowboy", texts: ["Японско-американская певица в её лучшей форме. Краткие, плотные песни.", "Альбом из 14 треков общей длительностью 33 минуты. Митски ничего не растягивает."]),
        .init(artist: "frank ocean", album: "channel orange", texts: ["Современный соул в самой утончённой форме.", "За неделю до релиза Оушен написал в блоге об отношениях с мужчиной. Первый такой жест в хип-хоп/соул среде."]),
        .init(artist: "solange", album: "when i get home", texts: ["Альбом-сон, посвящённый Хьюстону — родному городу Соланж.", "Альбом сопровождается короткометражным фильмом. Это уже не альбом, а мультимедийная работа."]),
        .init(artist: "anderson .paak", album: "malibu", texts: ["Нео-соул, фанк, хип-хоп — всё смешано. Голос .Paak узнаваем с первой ноты.", "До альбома .Paak записывал под именем Breezy Lovejoy. Никто его не слушал. После — все."]),
        .init(artist: "childish gambino", album: "«awaken, my love!»", texts: ["Дональд Гловер сменил рэп на фанк. Альбом — оммаж Funkadelic и Sly Stone.", "Гловер исполнил весь альбом с детским хором при записи. Эффект — звук «детства, которого не было»."]),
        .init(artist: "janelle monáe", album: "dirty computer", texts: ["Концептуальный альбом-фильм. Поп, ритм-н-блюз, фанк, политика.", "Сопровождался короткометражным «эмоциональным фильмом». Прежде такого не делал никто."]),
        .init(artist: "tyler, the creator", album: "igor", texts: ["Альбом про неразделённую любовь к мужчине. Тайлер вышел за рамки хип-хопа.", "Получил «Грэмми» в категории «лучший рэп-альбом», хотя сам Тайлер протестовал — «Это не рэп»."]),
        .init(artist: "fiona apple", album: "fetch the bolt cutters", texts: ["Записано в домашней студии в Венис-Бич. Импровизация, ритм палочками о стол.", "19 студийных вариаций — Фиона отбирала после многолетней работы. Первый «совершенный» альбом 2020-х по версии Pitchfork."]),
        .init(artist: "the weeknd", album: "after hours", texts: ["Поп-нуар. Альбом, который вернул синтвейв в мейнстрим.", "«Blinding Lights» — самый успешный сингл всех времён по чартам Billboard. Удерживал высокие позиции более года."]),
        .init(artist: "billie eilish", album: "when we all fall asleep, where do we go?", texts: ["Дебют записан в спальне с братом. Билли было 17.", "Самый успешный дебют 2010-х. Альбом стал #1 в 17 странах."]),
        .init(artist: "lorde", album: "pure heroine", texts: ["Дебют 16-летней певицы из Новой Зеландии. «Royals» — глобальный хит.", "Лорд написала альбом, ещё учась в школе. «Royals» — единственный сингл в истории #1 Billboard, написанный девочкой-подростком из Окленда."]),
        .init(artist: "mac miller", album: "swimming", texts: ["Последний альбом Маллера, выпущенный при жизни. Через месяц после релиза он умер от передозировки.", "Альбом — рефлексия о выздоровлении от наркомании. Маллер был на пороге зрелости и потерял её."]),
